const query = $('Trigger desde Agente').first().json.query.toLowerCase();
const kbItems = $('Leer Knowledge Base').all();

// Buscar coincidencias en keywords y questions
const results = [];

for (const item of kbItems) {
  const keywords = (item.json.KEYWORDS || '').toLowerCase();
  const question = (item.json.QUESTION || '').toLowerCase();
  const category = (item.json.CATEGORY || '').toLowerCase();
  const answer = item.json.ANSWER || '';

  // Calcular relevancia
  let score = 0;
  const queryWords = query.split(/\s+/);

  for (const word of queryWords) {
    if (word.length < 3) continue; // Ignorar palabras muy cortas

    if (keywords.includes(word)) score += 3;
    if (question.includes(word)) score += 2;
    if (category.includes(word)) score += 1;
  }

  if (score > 0) {
    results.push({
      category: item.json.CATEGORY,
      question: item.json.QUESTION,
      answer: answer,
      score: score
    });
  }
}

// Ordenar por relevancia y tomar top 3
results.sort((a, b) => b.score - a.score);
const topResults = results.slice(0, 3);

if (topResults.length === 0) {
  return [{
    json: {
      response: "I don't have specific information about that in my knowledge base. I can offer to have Nataly Riaño follow up with more details. Would that be helpful?"
    }
  }];
}

// Formatear respuesta
let response = '';
for (const result of topResults) {
  response += `${result.answer}\n\n`;
}

return [{
  json: {
    response: response.trim(),
    sources: topResults.map(r => r.question)
  }
}];
